mapper.select:
SELECT id, name, plan, credit
FROM users
WHERE id = #{userId}

SELECT * FROM ( SELECT 'FIT_ANALYSIS' AS type, ac.id AS application_case_id, ac.company_name, ac.job_title, CONCAT(ac.company_name, ' ', ac.job_title, ' 적합도 분석 완료 · ', fa.fit_score, '점') AS content, fa.created_at AS occurred_at, fa.fit_score AS score FROM fit_analysis fa INNER JOIN application_case ac ON ac.id = fa.application_case_id WHERE ac.user_id = #{userId}
UNION ALL
SELECT 'INTERVIEW' AS type, ac.id AS application_case_id, ac.company_name, ac.job_title, CONCAT( ac.company_name, ' ', ac.job_title, ' 모의면접 ', IF(interview.total_score IS NULL, '진행', CONCAT('완료 · ', interview.total_score, '점')) ) AS content, COALESCE(interview.ended_at, interview.started_at, interview.created_at) AS occurred_at, interview.total_score AS score FROM interview_session interview INNER JOIN application_case ac ON ac.id = interview.application_case_id WHERE ac.user_id = #{userId}
UNION ALL
SELECT 'APPLICATION' AS type, ac.id AS application_case_id, ac.company_name, ac.job_title, CONCAT(ac.company_name, ' ', ac.job_title, ' 지원 건 업데이트') AS content, ac.updated_at AS occurred_at, NULL AS score FROM application_case ac WHERE ac.user_id = #{userId} ) activities ORDER BY occurred_at DESC LIMIT 6
